
import base64, gzip
from flask import Flask, Response

app = Flask(__name__)

_HTML_B64 = ""

@app.route("/")
def index():
    html = gzip.decompress(base64.b64decode(_HTML_B64)).decode("utf-8")
    return Response(html, mimetype="text/html")

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8080)
